import{_ as a,o as t,c as n,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Web Testing","description":"","frontmatter":{"title":"Web Testing","slug":"web-testing"},"headers":[],"relativePath":"developer-hub/web-testing.md","filePath":"developer-hub/web-testing.md"}'),s={name:"developer-hub/web-testing.md"};function i(r,e,l,h,p,c){return t(),n("div",null,[...e[0]||(e[0]=[o(`<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The testing tools and resources in this guide help you make sure that you&#39;ve integrated the Branch Web SDK correctly.</p><p>To integrate the Branch Web SDK, follow the steps in our Web SDK Basic Integration <a href="./web-basic-integration.html">guide</a>.</p><h2 id="test-scenarios" tabindex="-1">Test Scenarios <a class="header-anchor" href="#test-scenarios" aria-label="Permalink to &quot;Test Scenarios&quot;">​</a></h2><h3 id="test-reading-deep-link" tabindex="-1">Test Reading Deep Link <a class="header-anchor" href="#test-reading-deep-link" aria-label="Permalink to &quot;Test Reading Deep Link&quot;">​</a></h3><p>Reading a Branch Deep Link means retrieving the data from it. You can learn about how to do this in our Web SDK Advanced Features <a href="https://help.branch.io/developers-hub/docs/web-advanced-features#read-deep-link" target="_blank" rel="noreferrer">guide</a>.</p><p>To test reading a Branch Deep Link, first add a fallback URL to the Deep Link that points to your website:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://example.app.link/kJNbhZ1PrF?$fallback_url=https://example.com</span></span></code></pre></div><p>The website in the fallback URL will open, and a value called <code>_branch_match_id</code> will get appended to the Deep Link:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://example.app.link/kJNbhZ1PrF?$fallback_url=https://www.website.com/&amp;_branch_match_id=418480444086051524</span></span></code></pre></div><p>You can now try to read the <code>_branch_match_id</code> from the <code>$fallback_url</code> website:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>branch.init(&#39;key_live_YOUR_KEY_GOES_HERE&#39;, function(err, data) {</span></span>
<span class="line"><span>  console.log(err, data);</span></span>
<span class="line"><span>});</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Read latest data</span></span>
<span class="line"><span>branch.data(function(err, data) {</span></span>
<span class="line"><span>  console.log(err, data);</span></span>
<span class="line"><span>});</span></span></code></pre></div><h2 id="testing-tools" tabindex="-1">Testing Tools <a class="header-anchor" href="#testing-tools" aria-label="Permalink to &quot;Testing Tools&quot;">​</a></h2><h3 id="integration-status-tab" tabindex="-1">Integration Status Tab <a class="header-anchor" href="#integration-status-tab" aria-label="Permalink to &quot;Integration Status Tab&quot;">​</a></h3><p>For a quick approach to checking your Branch Web SDK integration status and progress, you can use the <a href="https://branch.dashboard.branch.io/integration" target="_blank" rel="noreferrer">Integration Status</a> tab of the Branch Dashboard.</p><h3 id="link-debugger" tabindex="-1">Link Debugger <a class="header-anchor" href="#link-debugger" aria-label="Permalink to &quot;Link Debugger&quot;">​</a></h3><p>You can make sure your Branch Link is properly configured by using Branch&#39;s Link Debugger tool. It can help you determine whether the link was properly configured and passed the correct data when it was created.</p><p>To use Branch&#39;s Link Debugger:</p><ol><li><p>Sign in to your <a href="https://branch.dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Make sure you are in the proper environment for the link you want to debug (live or test).</p></li><li><p>Copy the Branch Link, and append <code>?debug=1</code> to the end of it.</p><ol><li>For example, the Branch Link <code>https://branchster.app.link/3vqEJflHrGb</code> would become <code>https://branchster.app.link/3vqEJflHrGb?debug=1</code></li></ol></li><li><p>Paste this link, including the <code>?debug=1</code> flag, into your browser. This will open the Link Debugger view: .png)</p></li></ol><h2 id="additional-resources" tabindex="-1">Additional Resources <a class="header-anchor" href="#additional-resources" aria-label="Permalink to &quot;Additional Resources&quot;">​</a></h2><h4 id="sample-application" tabindex="-1">Sample Application <a class="header-anchor" href="#sample-application" aria-label="Permalink to &quot;Sample Application&quot;">​</a></h4><p>The following sample application allows you to test creating Branch Events, Links, QR Codes, and Journeys.</p><p>Use the <a href="./web-full-reference.html">Branch SDK Web Full Reference</a> guide for definitions and code samples related to methods used in the sample application.</p><p>To use the demo:</p><ol><li><p>Visit the Branch Web SDK <a href="https://cdn.us.document360.io/082e8be0-ad38-4650-9062-689a75e517a2/Images/Documentation/example.html" target="_blank" rel="noreferrer">sample application</a> live page.</p></li><li><p>In the <strong>API Settings</strong> section, enter in your Branch Live Key, which you can find in the <strong>Account Settings</strong> <a href="https://dashboard.branch.io/account-settings/profile" target="_blank" rel="noreferrer">page</a> of your Branch Dashboard.</p></li><li><p>Click the <strong>Update API Settings</strong> button.</p></li><li><p>To test sending Branch Events, click the <strong>Create Custom Event</strong> button. If you would like to see the headers and payload associated with the event, you can do so using the <strong>Network</strong> tab of browser&#39;s developer tools.</p></li><li><p>To confirm that a Branch Event was sent successfully, go to the <strong>Liveview</strong> <a href="https://branch.dashboard.branch.io/liveview/events" target="_blank" rel="noreferrer">page</a> of the Branch Dashboard and filter by <strong>custom event</strong>. Please note that it may take a few minutes to see your events show up.</p></li><li><p>Explore the rest of the sample application using the available buttons, and see what is sent in the request and what is returned in the response when you do so.</p></li><li><p>Review the project on <a href="https://github.com/BranchMetrics/web-branch-deep-linking-attribution/blob/master/src/web/example.template.html" target="_blank" rel="noreferrer">GitHub</a> to see how the different Branch Web SDK methods are used in the sample application.</p></li></ol><h3 id="troubleshooting-guide" tabindex="-1">Troubleshooting Guide <a class="header-anchor" href="#troubleshooting-guide" aria-label="Permalink to &quot;Troubleshooting Guide&quot;">​</a></h3><p>If you&#39;re experiencing unexpected behavior with the Branch Web SDK, start by taking a look at our Troubleshooting <a href="./web-troubleshooting.html">guide</a>.</p>`,27)])])}const b=a(s,[["render",i]]);export{u as __pageData,b as default};
